let {gridProps} = useGridList(
  {
    ...DOMCollectionProps,
    keyboardDelegate,
    // Only tab navigation is supported in grid layout.
    keyboardNavigationBehavior: layout === 'grid' ? 'tab' : keyboardNavigationBehavior,
    isVirtualized,
    shouldSelectOnPressUp: props.shouldSelectOnPressUp,
    disallowTypeAhead,
    focusOnEntry
  },
  filteredState,
  ref
);

useLayoutEffect(() => {
    if (collectionNode != null) {
      // When typing forward, we want to delay the setting of active descendant to not interrupt the native screen reader announcement
      // of the letter you just typed. If we recieve another focus event then we clear the queued update
      collectionNode.addEventListener('focusin', updateActiveDescendantEvent);
    }
    return () => {
      collectionNode?.removeEventListener('focusin', updateActiveDescendantEvent);
    };
  }, [collectionNode]);

let {itemProps, isPressed} = useSelectableItem({
  selectionManager: manager,
  key,
  ref,
  isDisabled,
  // Link tabs should behave like native anchors (navigate on press up)
  // This avoids reopening beforeunload dialogs when browsers replay
  // queued pointer enter/leave events after cancellation.
  shouldSelectOnPressUp: shouldSelectOnPressUp ?? item?.props.href != null,
  linkBehavior: 'selection'
});

let sliderState = useSliderState({
  ...color.getChannelRange(channel),
  ...otherProps,
  numberFormatter,
  value: color.getChannelValue(channel),
  defaultValue: defaultColor.getChannelValue(channel),
  onChange(v) {
    setColor(color.withChannelValue(channel, v));
  },
  onChangeEnd(v) {
    // onChange will have already been called with the right value, this is just to trigger onChangeEnd
    if (props.onChangeEnd) {
      props.onChangeEnd(color.withChannelValue(channel, v));
    }
  }
});

const useValidate = useCallback<FormStore["useValidate"]>(
  (callback) => {
    callback = useEvent(callback);
    // Whenever the items change (for example, when form fields are lazily
    // rendered), we need to reset the callbacks so they always run in a
    // consistent order.
    const items = useStoreState(store, "items");
    useEffect(() => store.onValidate(callback), [items, callback]);
  },
  [store],
);

const expandGroup = useCallback(
  (group?: ButtonDropdownProps.ItemGroup) => {
    const groupIndex = group ? getItemIndex(group) : targetIndex;
    const firstChildIndex = [...groupIndex, 0];

    // move to the first child item unless in restricted mode
    setTargetIndex(isInRestrictedView ? groupIndex : firstChildIndex);
    setExpandedIndex(groupIndex);
  },
  [targetIndex, getItemIndex, isInRestrictedView]
);

let triggerLoadMore = useEffectEvent((entries: IntersectionObserverEntry[]) => {
  // Use "isIntersecting" over an equality check of 0 since it seems like there is cases where
  // a intersection ratio of 0 can be reported when isIntersecting is actually true
  for (let entry of entries) {
    // Note that this will be called if the collection changes, even if onLoadMore was already called and is being processed.
    // Up to user discretion as to how to handle these multiple onLoadMore calls
    if (entry.isIntersecting && onLoadMore) {
      onLoadMore();
    }
  }
});

let increment = () => {
  let newValue = addColorValue(parsedValue, step);
  // if we've arrived at the same value that was previously in the state, the
  // input value should be updated to match
  // ex type 4, press increment, highlight the number in the input, type 4 again, press increment
  // you'd be at 5, then incrementing to 5 again, so no re-render would happen and 4 would be left in the input
  if (newValue === colorValue) {
    setInputValue(newValue.toString('hex'));
  }
  safelySetColorValue(newValue);
  validation.commitValidation();
};

let decrement = () => {
  let newValue = addColorValue(parsedValue, -step);
  // if we've arrived at the same value that was previously in the state, the
  // input value should be updated to match
  // ex type 4, press increment, highlight the number in the input, type 4 again, press increment
  // you'd be at 5, then incrementing to 5 again, so no re-render would happen and 4 would be left in the input
  if (newValue === colorValue) {
    setInputValue(newValue.toString('hex'));
  }
  safelySetColorValue(newValue);
  validation.commitValidation();
};

const { __internalRootRef } = useBaseComponent('CollectionPreferences', {
  props: {},
  metadata: {
    ...parentMetadata,
    hasStripedRowsPreference: !!stripedRowsPreference,
    hasVisibleContentPreference: !!visibleContentPreference,
    hasContentDisplayPreference: !!contentDisplayPreference,
    hasContentDensityPreference: !!contentDensityPreference,
    hasStickyColumnsPreference: !!stickyColumnsPreference,
    hasContentDisplayColumnFiltering: !!contentDisplayPreference?.enableColumnFiltering,
    visibleContentOptionsCount: visibleContentPreference?.options?.length,
  },
});

const baseComponentProps = useBaseComponent(
  'ExpandableSection',
  {
    props: {
      disableContentPaddings: props.disableContentPaddings,
      headingTagOverride: props.headingTagOverride,
      variant,
    },
    metadata: {
      hasInstanceIdentifier: Boolean(analyticsMetadata?.instanceIdentifier),
      hasHeaderActions: Boolean(props.headerActions),
    },
  },
  analyticsMetadata
);

const [
    { highlightType, highlightedOption, highlightedIndex },
    {
      moveHighlightWithKeyboard,
      resetHighlightWithKeyboard,
      setHighlightedIndexWithMouse,
      highlightOptionWithKeyboard,
      highlightFirstOptionWithMouse,
      goHomeWithKeyboard,
      goEndWithKeyboard,
    },
  ] = useHighlightedOption({ options: options, isHighlightable });

let getSnapshot = useCallback(() => {
    let collection = document.getCollection();
    if (document.isSSR) {
      // After SSR is complete, reset the document to empty so it is ready for React to render the portal into.
      // We do this _after_ getting the collection above so that the collection still has content in it from SSR
      // during the current render, before React has finished the client render.
      document.resetAfterSSR();
    }
    return collection;
  }, [document]);

return {
  meterProps: {
    ...progressBarProps,
    // Use the meter role if available, but fall back to progressbar if not
    // Chrome currently falls back from meter automatically, and Firefox
    // does not support meter at all. Safari 13+ seems to support meter properly.
    // https://bugs.chromium.org/p/chromium/issues/detail?id=944542
    // https://bugzilla.mozilla.org/show_bug.cgi?id=1460378
    role: 'meter progressbar'
  },
  labelProps
};

let {itemProps, isFocused} = useSelectableItem({
  id,
  selectionManager: selectionManager,
  key,
  ref,
  shouldSelectOnPressUp: true,
  allowsDifferentPressOrigin: true,
  // Disable all handling of links in useSelectable item
  // because we handle it ourselves. The behavior of menus
  // is slightly different from other collections because
  // actions are performed on key down rather than key up.
  linkBehavior: 'none',
  shouldUseVirtualFocus: data.shouldUseVirtualFocus
});
